// Override fetch dla parts.json - zwraca embedded data
(function() {
  const _origFetch = window.fetch;
  window.fetch = function(url, options) {
    // Sprawdź czy URL zawiera parts.json (różne ścieżki)
    if (typeof url === 'string' && url.includes('parts.json')) {
      console.log('📦 Używam EMBEDDED_PARTS (' + window.EMBEDDED_PARTS.length + ' części)');
      return Promise.resolve({
        ok: true,
        status: 200,
        json: () => Promise.resolve(window.EMBEDDED_PARTS),
        text: () => Promise.resolve(JSON.stringify(window.EMBEDDED_PARTS))
      });
    }
    return _origFetch.call(this, url, options);
  };
})();
